        return orders.stream().filter(o -> o.getCreatedAt().toLocalDate().isEqual(today)).count();
    }

    public BigDecimal dailySale() {
        LocalDate today = LocalDate.now();
        return orders.stream()
                .filter(o -> o.getCreatedAt().toLocalDate().isEqual(today))
                .map(Order::getTotalAmount)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    public List<Order> ordersToday() {
        LocalDate today = LocalDate.now();
        return orders.stream().filter(o -> o.getCreatedAt().toLocalDate().isEqual(today)).toList();
    }
}

import java.sql.*;
public class T2 {
    public static void main(String[] a) throws Exception {
        String[] regions = {"ap-south-1","ap-southeast-1","us-east-1","us-west-1","eu-west-1","eu-central-1"};
        for (String r : regions) {
            test("jdbc:postgresql://aws-0-"+r+".pooler.supabase.com:5432/postgres?sslmode=require",
                 "postgres.eclxsguomhhelpjxmvon", "Wahaguruji$1313", r);
        }
    }
    static void test(String url, String u, String p, String label) {
        System.out.print(label + " ... ");
        try (Connection c = DriverManager.getConnection(url, u, p)) {
            System.out.println("OK DB=" + c.getCatalog());
        } catch (Exception e) { System.out.println("FAIL: " + e.getMessage()); }
    }
}
